defs.script:
/**
 * Отвечает за генерацию SVG-элементов (<g> и <circle>),
 * их добавление в DOM и удаление.
 */
class SVGMarkerManager {
    constructor(containerId) {
        this.containerId = containerId;
        this.ns = "http://www.w3.org/2000/svg";
    }

    get container() {
        return document.getElementById(this.containerId);
    }

    /**
     * Создает SVG-группу с маркерами, добавляет её в контейнер маркеров
     */
    createMarker(x, y, markerId, onAttachHandlers) {
        const markerContainer = this.container;
        if (!markerContainer) return;

        const markerGroup = document.createElementNS(this.ns, "g");
        markerGroup.setAttribute("id", markerId);
        markerGroup.setAttribute("data-id", markerId);
        markerGroup.setAttribute("data-type", "damage_marker");
        markerGroup.setAttribute("style", "cursor: pointer;");

        const circle = document.createElementNS(this.ns, "circle");
        circle.setAttribute("cx", x);
        circle.setAttribute("cy", y);
        circle.setAttribute("r", "5");
        circle.setAttribute("fill", "#FF0000");
        circle.setAttribute("stroke", "#FFFFFF");
        circle.setAttribute("stroke-width", "1");
        circle.setAttribute("data-type", "damage_marker");
        circle.setAttribute("data-id", markerId);

        markerGroup.appendChild(circle);
        markerContainer.appendChild(markerGroup);

        if (typeof onAttachHandlers === "function") {
            onAttachHandlers(markerGroup);
            onAttachHandlers(circle);
        }
    }

    /**
     * Удаляет маркер из DOM по ID.
     */
    removeMarker(markerId) {
        const markerElement = document.getElementById(markerId);
        if (markerElement) {
            markerElement.parentNode.removeChild(markerElement);
        }
    }

    /**
     * Полная очистка всех маркеров на схеме.
     */
    clearAll() {
        const markerContainer = this.container;
        if (markerContainer) markerContainer.innerHTML = "";
    }

    /**
     * Отрисовка массива переданных 2D маркеров.
     */
    highlightMarker(markers, onAttachHandlers) {
        this.clearAll();
        if (!markers) return;

        let parsed = typeof markers === 'string' ? JSON.parse(markers) : markers;
        if (!Array.isArray(parsed)) parsed = [parsed];

        parsed.forEach(data => {
            if (!data || data.x === undefined || data.y === undefined) return;
            const id = data.id || `marker_${Date.now()}_${Math.floor(Math.random() * 1000)}`;
            this.createMarker(parseFloat(data.x), parseFloat(data.y), id, onAttachHandlers);
        });
    }
}

/**
 * Отвечает за поиск деталей на SVG-панели и определение их родительских групп.
 */
class SVGModelManager {
    constructor(rootId) {
        this.root = document.getElementById(rootId);
    }

    /**
     * Ищет элемент детали на SVG по строковому имени.
     */
    findPart(partName) {
        if (!partName) return null;
        return this.root.querySelector(`[id^="${partName}"]`) ||
            this.root.querySelector(`[id*="${partName}"]`);
    }

    /**
     * Ищет ID детали вверх по DOM-дереву от места клика.
     */
    findPartId(targetElement) {
        let currentEl = targetElement;
        while (currentEl && currentEl !== this.root) {
            if (currentEl.id &&
                !currentEl.id.startsWith("line-") &&
                currentEl.id !== "lines" &&
                !currentEl.id.startsWith("marker_")) {
                return {id: currentEl.id, element: currentEl};
            }
            currentEl = currentEl.parentNode;
        }
        return null;
    }
}

/**
 * Принимает нормализованные координаты куба (nx, ny, nz) и проецирует их.
 */
class SVGProjector {
    /**
     * Проецирует трехмерную точку повреждения на плоскость 2D
     * @param {Object} damage - Объект повреждения из 3D
     * @param {SVGElement} svgPart - Найденный SVG элемент детали
     */
    static project3DTo2D(damage, svgPart) {
        const parentGroup = svgPart.closest("g");
        if (!parentGroup) {
            console.warn("Parent group not found for part:", damage.partName);
            return null;
        }

        const groupId = parentGroup.id.toLowerCase();
        const bbox = parentGroup.getBBox();

        let exactX = 0;
        let exactY = 0;

        if (groupId.includes("top")) {
            exactX = bbox.x + (1 - damage.nz) * bbox.width;
            exactY = bbox.y + damage.nx * bbox.height;
        } else if (groupId.includes("right")) {
            exactX = bbox.x + (1 - damage.nz) * bbox.width;
            exactY = bbox.y + damage.ny * bbox.height;
        } else if (groupId.includes("left")) {
            exactX = bbox.x + (1 - damage.nz) * bbox.width;
            exactY = bbox.y + (1 - damage.ny) * bbox.height;
        } else if (groupId.includes("front")) {
            exactX = bbox.x + damage.ny * bbox.width;
            exactY = bbox.y + damage.nx * bbox.height;

            if (/(light|grille)/i.test(damage.partName)) {
                exactX += 20;
            }

        } else if (groupId.includes("back")) {
            exactX = bbox.x + damage.ny * bbox.width;
            exactY = bbox.y + damage.nx * bbox.height;

            if (/(light|trunklid)/i.test(damage.partName)) {
                exactX -= 30;
            }

        } else {
            console.warn("Unknown SVG view group orientation:", groupId);
            return null;
        }

        return {
            id: damage.id,
            x: parseFloat(exactX.toFixed(2)),
            y: parseFloat(exactY.toFixed(2))
        };
    }
}

let modelManager, markerManager;
let pressedElement = null;
let pointerDownPos = {x: 0, y: 0};

const touchHighlightEffect = "0.3";

document.addEventListener("DOMContentLoaded", () => {
    modelManager = new SVGModelManager("svg-root");
    markerManager = new SVGMarkerManager("markers-container");

    attachTouchHandlers();
    initClickContainer();
});

/**
 * Вызывается нативной стороной для переноса точек из 3D в 2D.
 */
function load3DDamageToSVG(jsonFrom3D) {
    try {
        const damages = typeof jsonFrom3D === "string" ? JSON.parse(jsonFrom3D) : jsonFrom3D;
        const markersForSVG = [];

        damages.forEach(damage => {
            const has3DCords = damage.nx !== undefined && damage.ny !== undefined &&
                damage.nz !== undefined && (damage.nx !== 0 || damage.ny !== 0 || damage.nz !== 0);

            if (!has3DCords) {
                if (damage.x !== undefined && damage.y !== undefined) {
                    markersForSVG.push({id: damage.id,
                                        x: parseFloat(damage.x),
                                        y: parseFloat(damage.y)});
                }
                return;
            }

            const svgPart = modelManager.findPart(damage.partName);
            if (!svgPart) {
                console.warn("SVG part not found in DOM:", damage.partName);
                return;
            }

            const projectedPoint = SVGProjector.project3DTo2D(damage, svgPart);
            if (projectedPoint) {
                markersForSVG.push(projectedPoint);
            }
        });

        if (markersForSVG.length > 0) {
            highlightDamagedParts(markersForSVG);
        }

    } catch (error) {
        console.error("Projection error 3D to SVG:", error);
    }
}

/**
 * Сканирует документ и вешает события pointerdown на все интерактивные детали схемы.
 */
function attachTouchHandlers() {
    const elements = document.querySelectorAll("[id]");
    elements.forEach(el => {
        if (el.id === "svg-root" ||
            el.id === "lines" ||
            el.id === "markers-container" ||
            el.id.startsWith("line-")) return;
        attachTouchHandlersToElement(el);
    });
}

function attachTouchHandlersToElement(el) {
    if (!el) return;

    el.addEventListener("pointerdown", (e) => {
        pressedElement = e.target;
        pointerDownPos = {x: e.clientX, y: e.clientY};

        if (pressedElement.id?.startsWith("marker_") === false &&
            pressedElement.getAttribute("data-type") !== "damage_marker") {
            pressedElement.style.opacity = touchHighlightEffect;
        }
    });

    const resetOpacity = () => {
        if (pressedElement) {
            if (pressedElement.id?.startsWith("marker_") === false &&
                pressedElement.getAttribute("data-type") !== "damage_marker") {
                pressedElement.style.opacity = "1.0";
            }
            pressedElement = null;
        }
    };

    el.addEventListener("pointerleave", resetOpacity);
    el.addEventListener("pointercancel", resetOpacity);
}

/**
 * Инициализация глобального контейнера кликов.
 */
function initClickContainer() {
    const svgRoot = modelManager.root;

    svgRoot.addEventListener("pointerup", (e) => {
        if (!pressedElement) return;

        const moveDistance = Math.hypot(e.clientX - pointerDownPos.x, e.clientY - pointerDownPos.y);
        if (moveDistance > 8) {
            pressedElement = null;
            return;
        }

        const clickedTarget = e.target;

        if (clickedTarget.getAttribute("data-type") === "damage_marker" ||
            clickedTarget.id?.startsWith("marker_") ||
            clickedTarget.parentNode?.getAttribute("data-type") === "damage_marker") {

            const markerGroup = clickedTarget.closest("g[data-type='damage_marker']") ||
                (clickedTarget.id?.startsWith("marker_") ? clickedTarget : null);

            if (markerGroup) {
                const markerId = markerGroup.id || markerGroup.getAttribute("data-id");
                if (markerId) {
                    markerManager.removeMarker(markerId);

                    if (typeof elementClicked !== "undefined" && elementClicked.postMessage) {
                        elementClicked.postMessage(JSON.stringify({action: "marker_removed",
                                                                   id: markerId}));
                    }
                }
            }
            pressedElement = null;
            e.stopPropagation();
            return;
        }

        if (pressedElement && pressedElement.id?.startsWith("marker_") === false
            && pressedElement.getAttribute("data-type") !== "damage_marker") {
            pressedElement.style.opacity = "1.0";
        }

        const part = modelManager.findPartId(clickedTarget);
        if (!part || part.id === "svg-root") {
            pressedElement = null;
            return;
        }

        const cleanPartName = part.id.split("-")[0];

        const point = svgRoot.createSVGPoint();
        point.x = e.clientX;
        point.y = e.clientY;
        const svgP = point.matrixTransform(svgRoot.getScreenCTM().inverse());

        const parentGroup = part.element.closest("g");
        let viewType = "unknown";
        let nx_2d = 0, ny_2d = 0;

        if (parentGroup?.id) {
            const groupId = parentGroup.id.toLowerCase();
            const bbox = parentGroup.getBBox();

            nx_2d = (svgP.x - bbox.x) / bbox.width;
            ny_2d = (svgP.y - bbox.y) / bbox.height;

            if (groupId.includes("top")) viewType = "top";
            else if (groupId.includes("right")) viewType = "right";
            else if (groupId.includes("left")) viewType = "left";
            else if (groupId.includes("front")) viewType = "front";
            else if (groupId.includes("back")) viewType = "back";
        }

        const newMarkerId = `marker_${Date.now()}_${Math.floor(Math.random() * 1000)}`;

        const eventData = {
            action: "marker_added",
            id: newMarkerId,
            partName: cleanPartName,
            x: parseFloat(svgP.x.toFixed(2)),
            y: parseFloat(svgP.y.toFixed(2)),
            z: 0.0,
            nx_2d: nx_2d,
            ny_2d: ny_2d,
            viewType: viewType
        };

        if (typeof elementClicked !== "undefined" && elementClicked.postMessage) {
            elementClicked.postMessage(JSON.stringify(eventData));
        }

        markerManager.createMarker(svgP.x, svgP.y, newMarkerId, attachTouchHandlersToElement);
        pressedElement = null;
    });
}

function highlightDamagedParts(markers) {
    markerManager.highlightMarker(markers, attachTouchHandlersToElement);
}

window.load3DDamageToSVG = load3DDamageToSVG;
window.highlightDamagedParts = highlightDamagedParts;
window.clearAllMarkers = () => markerManager.clearAll();
window.removeMarkerById = (id) => markerManager.removeMarker(id);
